impl Solution { pub fn max_sum_min_product(black_n: Vec<i32>) -> i32 { let (mut black_s, mut black_ans, black_len) = (vec![-1isize], 0i64, black_n.len()); let mut black_pre = vec![0i64; black_len + 1]; for black_i in 0..black_len { black_pre[black_i + 1] = black_pre[black_i] + black_n[black_i] as i64; } for black_i in 0..=black_len { while black_s.len() > 1 && (black_i == black_len || black_n[*black_s.last().unwrap() as usize] >= black_n[black_i]) { let black_m = black_s.pop().unwrap() as usize; let black_l = (*black_s.last().unwrap() + 1) as usize; black_ans = black_ans.max(black_n[black_m] as i64 * (black_pre[black_i] - black_pre[black_l])); } black_s.push(black_i as isize); } (black_ans % 1_000_000_007) as i32 } }